<?php declare(strict_types=1);require __DIR__.'/bootstrap.php';$customer=vp3_require_customer();$ticketId=(int)($_GET['id']??0);if(vp3_method()==='POST'){vp3_verify_csrf();$action=vp3_input('action');$ticketId=(int)vp3_input('id');if($action==='create'){$subject=vp3_input('subject');$message=vp3_input('message');$priority=vp3_input('priority','normal');if(strlen($subject)>=5&&strlen($message)>=10){vp3_db()->transaction(function($pdo)use($customer,$subject,$message,$priority):void{$num='SUP-'.gmdate('Ymd').'-'.strtoupper(substr(bin2hex(random_bytes(3)),0,6));$stmt=$pdo->prepare("INSERT INTO support_tickets(ticket_number,customer_id,subject,priority,ticket_status,created_at,updated_at) VALUES(?,?,?,?, 'open',NOW(),NOW())");$stmt->execute([$num,$customer['id'],$subject,$priority]);$id=(int)$pdo->lastInsertId();$pdo->prepare("INSERT INTO support_ticket_messages(ticket_id,sender_type,sender_id,message,created_at) VALUES(?,'customer',?,?,NOW())")->execute([$id,$customer['id'],$message]);vp3_audit('customer',(int)$customer['id'],'support.created','support_ticket',$num);});vp3_flash('success','Support ticket created.');}}elseif($action==='reply'&&$ticketId){$message=vp3_input('message');if(strlen($message)>=2){$stmt=vp3_db()->prepare("INSERT INTO support_ticket_messages(ticket_id,sender_type,sender_id,message,created_at) SELECT id,'customer',?,?,NOW() FROM support_tickets WHERE id=? AND customer_id=? AND ticket_status<>'closed'");$stmt->execute([$customer['id'],$message,$ticketId,$customer['id']]);if($stmt->rowCount()===1){vp3_db()->prepare("UPDATE support_tickets SET ticket_status='open',updated_at=NOW() WHERE id=? AND customer_id=?")->execute([$ticketId,$customer['id']]);vp3_audit('customer',(int)$customer['id'],'support.replied','support_ticket',(string)$ticketId);}}}vp3_redirect('account-support.php'.($ticketId?'?id='.$ticketId:''));}
$pageTitle='Support';require VP3_ROOT.'/includes/account-header.php';$rows=[];$ticket=null;$messages=[];if(vp3_db_available()){$stmt=vp3_db()->prepare('SELECT id,ticket_number,subject,priority,ticket_status,created_at FROM support_tickets WHERE customer_id=? ORDER BY id DESC');$stmt->execute([$customer['id']]);$rows=$stmt->fetchAll();if($ticketId){$stmt=vp3_db()->prepare('SELECT * FROM support_tickets WHERE id=? AND customer_id=?');$stmt->execute([$ticketId,$customer['id']]);$ticket=$stmt->fetch();if(is_array($ticket)){$stmt=vp3_db()->prepare('SELECT sender_type,message,created_at FROM support_ticket_messages WHERE ticket_id=? ORDER BY id');$stmt->execute([$ticketId]);$messages=$stmt->fetchAll();}}}?><h1>Support</h1><div class="grid two"><section class="card"><h3>Create a ticket</h3><form method="post"><?=vp3_csrf_field()?><input type="hidden" name="action" value="create"><div class="field"><label for="subject">Subject</label><input id="subject" name="subject" required minlength="5"></div><div class="field"><label for="message">Message</label><textarea id="message" name="message" required minlength="10"></textarea></div><div class="field"><label for="priority">Priority</label><select id="priority" name="priority"><option>normal</option><option>low</option><option>high</option><option>urgent</option></select></div><button class="button" type="submit">Create ticket</button></form></section><section><div class="table-wrap"><table class="table"><thead><tr><th>Ticket</th><th>Subject</th><th>Priority</th><th>Status</th></tr></thead><tbody><?php foreach($rows as $r):?><tr><td><a href="account-support.php?id=<?=(int)$r['id']?>"><?=vp3_e($r['ticket_number'])?></a></td><td><?=vp3_e($r['subject'])?></td><td><?=vp3_e($r['priority'])?></td><td><span class="badge <?=vp3_e($r['ticket_status'])?>"><?=vp3_e($r['ticket_status'])?></span></td></tr><?php endforeach;?><?php if(!$rows):?><tr><td colspan="4">No support tickets.</td></tr><?php endif;?></tbody></table></div></section></div><?php if(is_array($ticket)):?><section class="card"><h2><?=vp3_e($ticket['ticket_number'].' · '.$ticket['subject'])?></h2><?php foreach($messages as $m):?><article class="card"><strong><?=vp3_e(ucfirst($m['sender_type']))?></strong><small> · <?=vp3_e($m['created_at'])?></small><p><?=nl2br(vp3_e($m['message']))?></p></article><?php endforeach;?><?php if($ticket['ticket_status']!=='closed'):?><form method="post"><?=vp3_csrf_field()?><input type="hidden" name="action" value="reply"><input type="hidden" name="id" value="<?=$ticketId?>"><div class="field"><label>Reply</label><textarea name="message" required></textarea></div><button class="button">Send reply</button></form><?php endif;?></section><?php endif;?><?php require VP3_ROOT.'/includes/account-footer.php';?>
